from typing import Dict, List, Optional, Any
from enum import Enum
from dataclasses import dataclass
from decimal import Decimal

class UserTier(Enum):
    BASIC = "basic"
    PREMIUM = "premium"
    VIP = "vip"
    ADMIN = "admin"

class DiscountType(Enum):
    PERCENTAGE = "percentage"
    FIXED = "fixed"

@dataclass
class CartItem:
    product_id: str
    name: str
    price: Decimal
    quantity: int
    taxable: bool = True

@dataclass
class DiscountCode:
    code: str
    discount_type: DiscountType
    value: Decimal
    min_tier: UserTier
    admin_only: bool = False
    min_purchase: Decimal = Decimal('0')

@dataclass
class User:
    user_id: str
