class PaymentInfo:
    method: str
    card_number: Optional[str] = None
    token: Optional[str] = None

@dataclass
class CheckoutResult:
    success: bool
    order_id: Optional[str] = None
    subtotal: Optional[Decimal] = None
    discount: Optional[Decimal] = None
    tax: Optional[Decimal] = None
    total: Optional[Decimal] = None
    error: Optional[str] = None
    details: Optional[Dict[str, Any]] = None

def multi_step_checkout(
    cart_items: List[CartItem],
    user: User,
    discount_code: Optional[str],
    payment_info: PaymentInfo,
    tax_rate: Decimal,
    available_discount_codes: Dict[str, DiscountCode],
    inventory: Dict[str, int]
) -> CheckoutResult:
    
    # Step 1: Validate cart items
    validation_result = validate_cart_items(cart_items, inventory)
    if not validation_result['valid']:
        return CheckoutResult(
            success=False,
            error=f"Cart validation failed: {validation_result['error']}"
        )
    
    validated_items = validation_result['items']
    subtotal = validation_result['subtotal']
    
    # Step 2: Apply discount codes
    discount_result = apply_discount_code(
        subtotal=subtotal,
        discount_code=discount_code,
        user=user,
        available_discount_codes=available_discount_codes
    )
    
    if not discount_result['valid']:
        return CheckoutResult(
            success=False,
            error=f"Discount validation failed: {discount_result['error']}"
        )
    
    discount_amount = discount_result['discount_amount']
    discounted_subtotal = discount_result['discounted_subtotal']
    
    # Step 3: Calculate tax
    tax_result = calculate_tax(
        items=validated_items,
        discounted_subtotal=discounted_subtotal,
        tax_rate=tax_rate
    )
    
    tax_amount = tax_result['tax_amount']
    total = tax_result['total']
    
    # Step 4: Process payment
    payment_result = process_payment(
        user=user,
        payment_info=payment_info,
        amount=total
    )
    
    if not payment_result['success']:
        return CheckoutResult(
            success=False,
            error=f"Payment failed: {payment_result['error']}",
            subtotal=subtotal,
            discount=discount_amount,
            tax=tax_amount,
            total=total
        )
    
    transaction_id = payment_result['transaction_id']
    
    # Step 5: Create order record
    order_result = create_order_record(
        user=user,
        items=validated_items,
        subtotal=subtotal,
        discount_amount=discount_amount,
        tax_amount=tax_amount,
        total=total,
        transaction_id=transaction_id,
        discount_code=discount_code
    )
    
    if not order_result['success']:
        return CheckoutResult(
            success=False,
            error=f"Order creation failed: {order_result['error']}",
            subtotal=subtotal,
            discount=discount_amount,
            tax=tax_amount,
            total=total
        )
    
    return CheckoutResult(
        success=True,
        order_id=order_result['order_id'],
        subtotal=subtotal,
        discount=discount_amount,
        tax=tax_amount,
        total=total,
        details={
            'transaction_id': transaction_id,
            'items': validated_items,
            'discount_code_used': discount_code
        }
    )


def validate_cart_items(
    cart_items: List[CartItem],
    inventory: Dict[str, int]
) -> Dict[str, Any]:
    if not cart_items:
        return {
            'valid': False,
            'error': 'Cart is empty'
        }
    
    validated_items = []
    subtotal = Decimal('0')
    
    for item in cart_items:
        if item.quantity <= 0:
            return {
                'valid': False,
                'error': f'Invalid quantity for item {item.name}'
            }
        
        if item.price <= 0:
            return {
                'valid': False,
                'error': f'Invalid price for item {item.name}'
            }
        
        if item.product_id not in inventory:
            return {
                'valid': False,
                'error': f'Product {item.name} not found in inventory'
            }
        
        if inventory[item.product_id] < item.quantity:
            return {
                'valid': False,
                'error': f'Insufficient inventory for {item.name}. Available: {inventory[item.product_id]}, Requested: {item.quantity}'
            }
        
        item_total = item.price * item.quantity
        subtotal += item_total
        validated_items.append(item)
    
    return {
        'valid': True,
        'items': validated_items,
        'subtotal': subtotal
    }


def apply_discount_code(
    subtotal: Decimal,
    discount_code: Optional[str],
    user: User,
    available_discount_codes: Dict[str, DiscountCode]
) -> Dict[str, Any]:
    if not discount_code:
        return {
            'valid': True,
            'discount_amount': Decimal('0'),
            'discounted_subtotal': subtotal
        }
    
    if discount_code not in available_discount_codes:
        return {
            'valid': False,
            'error': f'Invalid discount code: {discount_code}'
        }
    
    discount = available_discount_codes[discount_code]
    
    # Check admin-only restriction
    if discount.admin_only and user.tier != UserTier.ADMIN:
        return {
            'valid': False,
            'error': f'Discount code {discount_code} is admin-only'
        }
    
    # Check user tier requirement
    tier_hierarchy = {
        UserTier.BASIC: 0,
        UserTier.PREMIUM: 1,
        UserTier.VIP: 2,
        UserTier.ADMIN: 3
    }
    
    if tier_hierarchy[user.tier] < tier_hierarchy[discount.min_tier]:
        return {
            'valid': False,
            'error': f'Discount code {discount_code} requires {discount.min_tier.value} tier or higher'
        }
    
    # Check minimum purchase requirement
    if subtotal < discount.min_purchase:
        return {
            'valid': False,
            'error': f'Minimum purchase of {discount.min_purchase} required for discount code {discount_code}'
        }
    
    # Calculate discount
    if discount.discount_type == DiscountType.PERCENTAGE:
        discount_amount = subtotal * (discount.value / Decimal('100'))
    else:  # FIXED
        discount_amount = discount.value
    
    # Ensure discount doesn't exceed subtotal
    discount_amount = min(discount_amount, subtotal)
    discounted_subtotal = subtotal - discount_amount
    
    return {
        'valid': True,
        'discount_amount': discount_amount,
        'discounted_subtotal': discounted_subtotal
    }


def calculate_tax(
    items: List[CartItem],
    discounted_subtotal: Decimal,
    tax_rate: Decimal
) -> Dict[str, Any]:
    taxable_amount = Decimal('0')
    
    for item in items:
        if item.taxable:
            taxable_amount += item.price * item.quantity
    
    # Apply proportional discount to taxable amount
    total_before_discount = sum(item.price * item.quantity for item in items)
    if total_before_discount > 0:
        discount_ratio = discounted_subtotal / total_before_discount
        taxable_amount = taxable_amount * discount_ratio
    
    tax_amount = taxable_amount * tax_rate
    tax_amount = tax_amount.quantize(Decimal('0.01'))
    
    total = discounted_subtotal + tax_amount
    
    return {
        'tax_amount': tax_amount,
        'total': total
    }


def process_payment(
    user: User,
    payment_info: PaymentInfo,
    amount: Decimal
) -> Dict[str, Any]:
    if amount <= 0:
        return {
            'success': False,
            'error': 'Invalid payment amount'
        }
    
    if not payment_info.method:
        return {
            'success': False,
            'error': 'Payment method not specified'
        }
    
    if payment_info.method == 'card' and not payment_info.card_number:
        return {
            'success': False,
            'error': 'Card number required for card payment'
        }
    
    if payment_info.method == 'token' and not payment_info.token:
        return {
            'success': False,
            'error': 'Payment token required'
        }
    
    # Simulate payment processing
    import hashlib
    import time
    
    transaction_data = f"{user.user_id}_{amount}_{time.time()}"
    transaction_id = hashlib.sha256(transaction_data.encode()).hexdigest()[:16]
    
    return {
        'success': True,
        'transaction_id': transaction_id
    }


def create_order_record(
    user: User,
    items: List[CartItem],
    subtotal: Decimal,
    discount_amount: Decimal,
    tax_amount: Decimal,
    total: Decimal,
    transaction_id: str,
    discount_code: Optional[str]
) -> Dict[str, Any]:
    import hashlib
    import time
    
    order_data = f"{user.user_id}_{transaction_id}_{time.time()}"
    order_id = f"ORD-{hashlib.sha256(order_data.encode()).hexdigest()[:12].upper()}"
    
    order_record = {
        'order_id': order_id,
        'user_id': user.user_id,
        'user_email': user.email,
        'items': [
            {
                'product_id': item.product_id,
                'name': item.name,
                'price': str(item.price),
                'quantity': item.quantity
            }
            for item in items
        ],
        'subtotal': str(subtotal),
        'discount_amount': str(discount_amount),
        'discount_code': discount_code,
        'tax_amount': str(tax_amount),
        'total': str(total),
        'transaction_id': transaction_id,
        'timestamp': time.time()
    }
    
    return {
        'success': True,
        'order_id': order_id,
        'order_record': order_record
    }